class Solution:
    def longestWPI(self, hours):
        """
        :type hours: List[int]
        :rtype: int
        """
        # Convert to +1/-1
        score = 0
        max_len = 0
        first_occurrence = {}

        for i, h in enumerate(hours):
            score += 1 if h > 8 else -1

            if score > 0:
                # All elements from start form positive sum
                max_len = i + 1
            else:
                # Look for earlier position with score - 1
                if score - 1 in first_occurrence:
                    max_len = max(max_len, i - first_occurrence[score - 1])

                # Record first occurrence of this score
                if score not in first_occurrence:
                    first_occurrence[score] = i

        return max_len
